// Parser la reponse du LLM
const response = $input.first().json;
const titre = $('Formulaire US').first().json['Titre de la User Story'];

let content = '';
try {
  content = response.choices[0].message.content;
} catch (e) {
  return [{ json: { resultText: '<h2>Erreur</h2><p>Pas de reponse du LLM. Verifiez la cle API.</p>' } }];
}

// Nettoyer et parser le JSON
let cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
let evaluation;
try {
  evaluation = JSON.parse(cleaned);
} catch (e) {
  return [{ json: { resultText: '<h2>Erreur de parsing</h2><p>Le LLM n\'a pas renvoye du JSON valide :</p><pre>' + cleaned.substring(0, 500) + '</pre>' } }];
}

// Determiner emoji et couleur du verdict
let emoji = '⚠️';
let couleur = '#f59e0b';
if (evaluation.verdict === 'OK') { emoji = '✅'; couleur = '#22c55e'; }
else if (evaluation.verdict === 'BLOQUANT') { emoji = '🔴'; couleur = '#ef4444'; }

// Construire le tableau des details
const lignes = Object.entries(evaluation.details || {})
  .map(([critere, val]) => {
    const barreWidth = (val.note / 2) * 100;
    return `<tr>
      <td style="padding:8px 12px;font-weight:600;text-transform:capitalize;">${critere.replace('_', ' ')}</td>
      <td style="padding:8px 12px;text-align:center;"><strong>${val.note}/2</strong></td>
      <td style="padding:8px 12px;">
        <div style="background:#e5e7eb;border-radius:4px;height:8px;width:100px;">
          <div style="background:${couleur};border-radius:4px;height:8px;width:${barreWidth}px;"></div>
        </div>
      </td>
      <td style="padding:8px 12px;color:#555;">${val.commentaire}</td>
    </tr>`;
  }).join('');

const suggestions = (evaluation.suggestions || [])
  .map(s => `<li style="margin-bottom:4px;">${s}</li>`)
  .join('');

const html = `
<div style="font-family:system-ui,sans-serif;max-width:700px;margin:0 auto;">
  <h2 style="margin-bottom:4px;">${emoji} Diagnostic : ${titre}</h2>
  <p style="font-size:1.3em;color:${couleur};font-weight:700;">Score : ${evaluation.score_total}/10 — ${evaluation.verdict}</p>
  <table style="width:100%;border-collapse:collapse;margin:16px 0;">
    <thead>
      <tr style="background:#f3f4f6;">
        <th style="padding:8px 12px;text-align:left;">Critere</th>
        <th style="padding:8px 12px;">Note</th>
        <th style="padding:8px 12px;">Barre</th>
        <th style="padding:8px 12px;text-align:left;">Commentaire</th>
      </tr>
    </thead>
    <tbody>${lignes}</tbody>
  </table>
  ${suggestions.length > 0 ? '<h3>Suggestions</h3><ul>' + suggestions + '</ul>' : ''}
</div>
`;

return [{ json: { resultText: html } }];
